const input = $input.first().json;
const body = input.body || {};

const callbackQuery = body.callback_query || {};
const data = callbackQuery.data || '';
const fromId = callbackQuery.from ? callbackQuery.from.id : null;
const messageId = callbackQuery.message ? callbackQuery.message.message_id : null;

let action = null;
let runId = null;

if (data.startsWith('feedback_up_')) {
  action = 'thumbs_up';
  runId = data.replace('feedback_up_', '');
} else if (data.startsWith('feedback_down_')) {
  action = 'thumbs_down';
  runId = data.replace('feedback_down_', '');
} else if (data.startsWith('hitl_approve_')) {
  action = 'approve';
  runId = data.replace('hitl_approve_', '');
} else if (data.startsWith('hitl_reject_')) {
  action = 'reject';
  runId = data.replace('hitl_reject_', '');
}

return [{ json: { action, runId, fromId, messageId, callbackQueryId: callbackQuery.id } }];

const { execSync } = require('child_process');
const fs = require('fs');

const data = $input.first().json;
const action = $('Parse Callback Data').first().json.action;
const runId = $('Parse Callback Data').first().json.runId;

if (action !== 'thumbs_up' && action !== 'thumbs_down') {
  return [{ json: { reputation_sql: '-- no reputation update needed' } }];
}

const increment = action === 'thumbs_up' ? 'correct_count' : 'incorrect_count';

const sql = `LET $sources = (SELECT source FROM used_source WHERE run = (SELECT id FROM research_run WHERE run_id = '${runId}' LIMIT 1)[0].id); FOR $src IN $sources { UPDATE $src.source SET ${increment} += 1, reputation_score = (correct_count + 1) / (correct_count + incorrect_count + 2); };`;

return [{ json: { reputation_sql: sql } }];

const { execSync } = require('child_process');


const callbackData = $('Parse Callback Data').first().json;
const actionTexts = { thumbs_up: 'Danke! Positives Feedback gespeichert.', thumbs_down: 'Danke! Feedback gespeichert. Quellen-Reputation angepasst.', approve: 'Report approved und delivered.', reject: 'Report rejected.' };
const text = actionTexts[callbackData.action] || 'Verarbeitet.';

try {
  if (callbackData.callbackQueryId) {
    const body = JSON.stringify({ callback_query_id: callbackData.callbackQueryId, text });
    execSync(`curl -s -X POST -H "Content-Type: application/json" -d '${body.replace(/'/g, "'\\''")}'  "https://api.telegram.org/bot${$env.RESEARCH_BOT_TOKEN || ''}/answerCallbackQuery"`, {
      encoding: 'utf-8', timeout: 5000
    });
  }
} catch(e) {}

return [{ json: { answered: true, action: callbackData.action } }];
